module d_ff_sync (
    input wire clk,
    input wire rst,
    input wire d,
    output reg q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 1'b0;
        else
            q <= d;
    end

endmodule
